INSERT INTO room_types (property_id, name, name_zh, description, description_zh, price_per_night, max_guests, inventory, image_url, amenities, bed_type, view, size_sqm, occupancy, gallery, features, status, updated_at) VALUES (3, 'Standard Cabin', '標準船艙', 'Cozy cabin on board the Stay Madivaru boat, perfect for rest between ocean adventures.', '碧海灣船上溫馨舒適的船艙，是海上冒險之間放鬆休息的完美空間。', 3200, 2, 4, 'https://www.stayislands.mv/wp-content/uploads/2026/03/shutterstock_2264141839-1.webp', '["空調", "獨立浴室", "床頭燈", "收納空間", "海景窗"]', 'Twin', 'Ocean View', 12, '2 Adults', '["https://www.stayislands.mv/wp-content/uploads/2026/03/shutterstock_2264141839-1.webp", "https://www.stayislands.mv/wp-content/uploads/2026/03/shutterstock_2578452439-1-2-scaled.webp"]', '["雙床", "空調", "獨立浴室", "海景窗", "收納空間"]', 'available', unixepoch());
